var e=[{id:`L2_1`,type:`dialog`,speaker:`CHARLOTTE_ORDER_NULL_NULL`,text:{KOREA:`다들 정신 차려라! 전하께서 보고 계신다!`,JPN:`みんなしっかりしろ！　殿下がご観戦なさっている！`,ENG:`Keep it together! His Highness is watching even now!`,TWN:`大家振作點！殿下正看著呢！`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`CHARLOTTE_ORDER_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`CHARLOTTE_ORDER_NULL_NULL`,text:{KOREA:`그대들은 이미 죽은 자들이다! 어찌 죽음이 또 두렵단 말이냐!`,JPN:`そなたらはすでに死んだ身だ！　どうして死を恐れることがあろうか！`,ENG:`You’re already dead! How can death frighten you again?`,TWN:`你們是已死的人！還會怕死嗎！`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`CHARLOTTE_ORDER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`CHARLOTTE_ORDER_NULL_NULL`,text:{KOREA:`깃발은 꺾이지 않았다! 나와 함께 달려 나가자!`,JPN:`旗は折れていない！　私と共に駆け抜けよう！`,ENG:`Our banner still stands! Charge with me!`,TWN:`旗幟仍舊在飄揚！跟我一起衝吧！`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`CHARLOTTE_ORDER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`CHARLOTTE_ORDER_NULL_NULL`,text:{KOREA:`큿?!`,JPN:`くっ！？`,ENG:`Erck?!`,TWN:`咳？！`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`CHARLOTTE_ORDER_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`JAKE_DELTA_NEXT_NULL`,text:{KOREA:`여어, 등대털이범 아가씨. 오랜만이야.`,JPN:`よお、灯台荒らしのお嬢さん。久しぶりだな。`,ENG:`Yo, lighthouse raider-lady. Long time no see.`,TWN:`喂，燈塔小偷小姐，好久不見啦～`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`JAKE_DELTA_NEXT_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`JAKE_DELTA_NEXT_NULL`,text:{KOREA:`지난번에는 신세를 많이 졌었지.`,JPN:`この前は大変お世話になったぞ。`,ENG:`I owe you for last time.`,TWN:`上次受到你不少的照顧呢！`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`JAKE_DELTA_NEXT_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`JAKE_DELTA_NEXT_NULL`,text:{KOREA:`뭐, 꼭 나쁘지만은 않았어. 덕분에 이런 장비도 얻었으니까.`,JPN:`ま、悪いことばかりじゃなかったぜ。おかげでこんな装備も手に入れたし。`,ENG:`Well, I guess it wasn’t that bad. I got my hands on this gear thanks to you.`,TWN:`也不全都是壞事啦，至少我還有獲得這身裝備的嘛！`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`JAKE_DELTA_NEXT_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`JAKE_DELTA_NEXT_NULL`,text:{KOREA:`하지만 그렇다고 계속 빚지고만 살 수는 없지.`,JPN:`けど、ずっと世話になるわけにはいかないよな。`,ENG:`However, I don’t like to have outstanding debts.`,TWN:`不過也不能因為這樣，就一直欠你人情。`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`JAKE_DELTA_NEXT_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`JAKE_DELTA_NEXT_NULL`,text:{KOREA:`오늘은 기대하라고, 짜릿하게 해 줄 테니까.`,JPN:`今日は楽しみにしてろよ、ビリビリさせてやるからな。`,ENG:`I hope you’re prepared, because I’m gonna electrify you.`,TWN:`敬請期待，今天就給你個痛快！`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`JAKE_DELTA_NEXT_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`CHARLOTTE_ORDER_NULL_NULL`,text:{KOREA:`그때 만났던 번개의 전사인가……`,JPN:`あの時の稲妻の戦士か……`,ENG:`You must be the lightning warrior from last time...`,TWN:`是那時候遇到的閃電戰士嗎……`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:null,R:{char_id:`CHARLOTTE_ORDER_NULL_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L15_1`,type:`dialog`,speaker:`CHARLOTTE_ORDER_NULL_NULL`,text:{KOREA:`예전의 나라면…… 그대와의 싸움에서 어떤 의미도 느끼지 못했겠지.`,JPN:`昔の私なら……そなたとの闘いで何の意味も感じられなかっただろう。`,ENG:`Previously, I wouldn’t have felt anything from fighting against you.`,TWN:`若是以前的我……和你交手對我而言完全沒有任何意義。`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:null,R:{char_id:`CHARLOTTE_ORDER_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L16_1`,type:`dialog`,speaker:`CHARLOTTE_ORDER_NULL_NULL`,text:{KOREA:`하지만 지금은 내게도 승리를 해야 할 이유가 있어!`,JPN:`だが今は私にも勝つべき理由があるんだ！`,ENG:`However, I also have a reason to win now!`,TWN:`但現在的我，有非贏不可的理由！`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:null,R:{char_id:`CHARLOTTE_ORDER_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L17_1`,type:`dialog`,speaker:`JAKE_DELTA_NEXT_NULL`,text:{KOREA:`그거 좋군. 충고하는데 전력으로 덤비라고.`,JPN:`それはいいな。言っておくけど、全力で来いよ。`,ENG:`Sounds good. Just some advice, you’d better come at me with everything you’ve got.`,TWN:`非常好！我可是事先警告你，千萬不要有所保留。`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:{char_id:`JAKE_DELTA_NEXT_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`CHARLOTTE_ORDER_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L18_1`,type:`dialog`,speaker:`JAKE_DELTA_NEXT_NULL`,text:{KOREA:`이쪽은 신도 쓰러트린 적이 있으니까!`,JPN:`こちとら神にも勝ったことがあるんだからな！`,ENG:`After all, I’ve even defeated a god before!`,TWN:`畢竟我可是打倒過神的呢！`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:{char_id:`JAKE_DELTA_NEXT_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHARLOTTE_ORDER_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L21_1`,type:`dialog`,speaker:`LEESOOYEON_COFFIN_NULL_NULL`,text:{KOREA:`아군이 유리한 장소를 만들어내고 적에게 결전을 강요한다라……`,JPN:`味方に有利な場所を作り上げ、敵に決戦を迫る……`,ENG:`Creating an advantageous position for our troops and forcing the enemy into battle...`,TWN:`製造出對我方有利的地點後，強迫敵人開戰……`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`LEESOOYEON_COFFIN_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};